package com.taxin60sec.backend.controller;
import com.taxin60sec.backend.common.ApiResponse; import com.taxin60sec.backend.dto.infrastructure.AnalyticsDashboardDto; import com.taxin60sec.backend.entity.enums.WorkflowStage; import com.taxin60sec.backend.repository.*; import org.springframework.security.access.prepost.PreAuthorize; import org.springframework.web.bind.annotation.*; import java.math.BigDecimal; import java.util.*;
@RestController @RequestMapping("/api/v1/admin/infrastructure") @PreAuthorize("hasRole('ADMIN')")
public class InfrastructureController { private final CaseRepository cases; private final UserRepository users; private final ServiceOfferingRepository services; private final UploadedDocumentRepository documents; public InfrastructureController(CaseRepository cases,UserRepository users,ServiceOfferingRepository services,UploadedDocumentRepository documents){this.cases=cases;this.users=users;this.services=services;this.documents=documents;} @GetMapping("/analytics") public ApiResponse<AnalyticsDashboardDto> analytics(){Map<String,Long> stages=new LinkedHashMap<>();for(WorkflowStage stage:WorkflowStage.values())stages.put(stage.name(),cases.count((r,q,b)->b.equal(r.get("workflowStage"),stage)));long total=cases.count();long completed=stages.get(WorkflowStage.COMPLETED.name());return ApiResponse.success("Success",new AnalyticsDashboardDto(total,users.count(),services.count(),completed,0,BigDecimal.ZERO,total==0?0:(completed*100d/total),0,stages,Map.of()),null);} @GetMapping("/health") public ApiResponse<Map<String,String>> health(){return ApiResponse.success("Success",Map.of("application","UP","database","CONFIGURED","storage","NOT_CONFIGURED","email","NOT_CONFIGURED","payment","NOT_CONFIGURED","ai","NOT_CONFIGURED"),null);} }
